func (a *adapter) CreateApp(ctx context.Context, input app.CreateAppInput) (app.AppBase, error) {
	return transaction.Run(ctx, a, func(ctx context.Context) (app.AppBase, error) {
		return entutils.TransactingRepo(ctx, a, func(ctx context.Context, repo *adapter) (app.AppBase, error) {
			dbApp, err := repo.db.App.Create().SetNamespace(input.Namespace).SetName(input.Name).SetType(input.Type).SetStatus(app.AppStatusReady).Save(ctx)
			if err != nil { return app.AppBase{}, err }
			registryItem, err := repo.GetMarketplaceListing(ctx, app.MarketplaceGetInput{Type: dbApp.Type})
			if err != nil { return app.AppBase{}, err }
			return mapAppBaseFromDB(dbApp, registryItem), nil
		})
	})
}

func (h *handler) ListApps() ListAppsHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params ListAppsParams) (ListAppsRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return ListAppsRequest{}, err }
			return ListAppsRequest{Namespace: ns, Page: pagination.Page{PageSize: lo.FromPtrOr(params.PageSize, app.DefaultPageSize)}}, nil
		},
		func(ctx context.Context, req ListAppsRequest) (ListAppsResponse, error) {
			result, err := h.service.ListApps(ctx, req)
			if err != nil { return ListAppsResponse{}, err }
			items, _ := lo.MapE(result.Items, MapAppToAPI)
			return ListAppsResponse{Items: items, TotalCount: result.TotalCount}, nil
		},
		commonhttp.JSONResponseEncoderWithStatus[ListAppsResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("listApps"))...,
	)
}

func NewFactory(ctx context.Context, config Config) (*Factory, error) {
	if err := config.Validate(); err != nil { return nil, fmt.Errorf("failed to validate config: %w", err) }
	fact := &Factory{appService: config.AppService, billingService: config.BillingService}
	err := config.AppService.RegisterMarketplaceListing(ctx, app.RegistryItem{Listing: MarketplaceListing, Factory: fact})
	if err != nil { return nil, fmt.Errorf("failed to register marketplace listing: %w", err) }
	return fact, nil
}

func (s *Service) UpdateApp(ctx context.Context, input app.UpdateAppInput) (app.App, error) {
	if err := input.Validate(); err != nil { return nil, models.NewGenericValidationError(err) }
	existingApp, err := s.adapter.GetApp(ctx, input.AppID)
	if err != nil { return nil, err }
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (app.App, error) {
		existingBase := existingApp.GetAppBase()
		if err := s.hooks.PreUpdate(ctx, &existingBase); err != nil { return nil, err }
		updatedApp, err := s.adapter.UpdateApp(ctx, input)
		if err != nil { return nil, err }
		updatedBase := updatedApp.GetAppBase()
		if err := s.hooks.PostUpdate(ctx, &updatedBase); err != nil { return nil, err }
		event, err := app.NewAppUpdateEvent(ctx, updatedApp)
		if err != nil { return nil, err }
		return updatedApp, s.publisher.Publish(ctx, event)
	})
}

